file.content:
        if gt_acc == out_acc and gt_oct != out_oct:
            return "octave"
        if gt_oct == out_oct and gt_acc != out_acc:
            gt_midi = _pitch_to_midi(gt_pitch)
            out_midi = _pitch_to_midi(out_pitch)
            if gt_midi is not None and out_midi is not None and gt_midi == out_midi:
                return "enharmonic"
            return "accidental"

    # Step error: adjacent semitone (within 2 semitones)
    gt_midi = _pitch_to_midi(gt_pitch)
    out_midi = _pitch_to_midi(out_pitch)
    if gt_midi is not None and out_midi is not None and abs(gt_midi - out_midi) <= 2:
        return "step"

    # Cross-staff: large interval (>= 12 semitones = octave+) likely from wrong staff
    if gt_midi is not None and out_midi is not None and abs(gt_midi - out_midi) >= 12:
        return "cross_staff"

    return "far_pitch"


def compare_measure_staff(
    gt_notes: list[NoteInfo],
    out_notes: list[NoteInfo],
    measure_num: int,
    staff_num: int,
) -> list[ErrorInfo]:
    """Compare notes for one measure+staff, voice-agnostic."""
    # Sort by pitch then type for consistent ordering (voice-agnostic)
    gt_keys = sorted([n.key() for n in gt_notes])
    out_keys = sorted([n.key() for n in out_notes])

    if gt_keys == out_keys:
        return []

    errors: list[ErrorInfo] = []
    matcher = SequenceMatcher(None, gt_keys, out_keys)

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == "equal":
            continue
        elif tag == "replace":
            # Pair up substitutions
            gt_span = gt_keys[i1:i2]
            out_span = out_keys[j1:j2]
            for k in range(max(len(gt_span), len(out_span))):
                if k < len(gt_span) and k < len(out_span):
                    gp, gt_ = gt_span[k].split(":")
                    op, ot = out_span[k].split(":")
                    cat = classify_substitution(gp, op, gt_, ot)
                    if cat == "rhythm":
                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    else:
                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    errors.append(ErrorInfo(measure_num, staff_num, cat, detail))
                elif k < len(gt_span):
                    errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_span[k]))
                else:
                    errors.append(ErrorInfo(measure_num, staff_num, "extra", out_span[k]))
        elif tag == "delete":
            for k in range(i1, i2):
                errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_keys[k]))
        elif tag == "insert":
            for k in range(j1, j2):
                errors.append(ErrorInfo(measure_num, staff_num, "extra", out_keys[k]))

    return errors

def _first_measure_is_pickup(groups: list[SymbolChord], nominator: Fraction) -> bool:
    """Check if the first measure is a pickup (anacrusis) by comparing its duration
    to the expected measure duration (nominator = median measure duration).

    Uses first_dur <= nominator/2 as threshold to reduce false positives from
    TrOmr dropping notes from the first measure.
