                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    else:
                        detail = f"{gt_span[k]} -> {out_span[k]}"
                    errors.append(ErrorInfo(measure_num, staff_num, cat, detail))
                elif k < len(gt_span):
                    errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_span[k]))
                else:
                    errors.append(ErrorInfo(measure_num, staff_num, "extra", out_span[k]))
        elif tag == "delete":
            for k in range(i1, i2):
                errors.append(ErrorInfo(measure_num, staff_num, "missing", gt_keys[k]))
        elif tag == "insert":
            for k in range(j1, j2):
                errors.append(ErrorInfo(measure_num, staff_num, "extra", out_keys[k]))

    return errors


def diagnose(gt_path: str, out_path: str) -> None:
    """Run full diagnostic comparison and print results."""
    gt_measures = extract_measures(gt_path)
    out_measures = extract_measures(out_path)

    gt_nums = {m.measure_num for m in gt_measures}
    out_nums = {m.measure_num for m in out_measures}
    overlap = sorted(gt_nums & out_nums)

    # --- Section 1: Coverage ---
    print("=" * 60)
    print("COVERAGE")
    print("=" * 60)
    if gt_nums:
        gt_range = f"{min(gt_nums)}-{max(gt_nums)}"
    else:
        gt_range = "(none)"
    if out_nums:
        out_range = f"{min(out_nums)}-{max(out_nums)}"
    else:
        out_range = "(none)"
    print(f"  Ground truth:  {len(gt_nums)} measures ({gt_range})")
    print(f"  Output:        {len(out_nums)} measures ({out_range})")
    print(f"  Overlap:       {len(overlap)} measures")
    if gt_nums:
        pct = 100 * len(overlap) / len(gt_nums)
        print(f"  Coverage:      {pct:.0f}%")
    print()

    if not overlap:
        print("No overlapping measures to compare.")
        return

    # Build lookup dicts
    gt_by_num = {m.measure_num: m for m in gt_measures}
    out_by_num = {m.measure_num: m for m in out_measures}

    # Collect all staves across both files
    all_staves: set[int] = set()
    for num in overlap:
        all_staves.update(gt_by_num[num].notes_by_staff.keys())
        all_staves.update(out_by_num[num].notes_by_staff.keys())

    # --- Section 2: Measure-by-measure diffs ---
    print("=" * 60)
    print("MEASURE-BY-MEASURE DIFFS (errors only)")
    print("=" * 60)

    all_errors: list[ErrorInfo] = []
    perfect_measures = 0
    compared_measures = 0

    for num in overlap:
        gt_m = gt_by_num[num]
        out_m = out_by_num[num]
        measure_errors: list[ErrorInfo] = []

        staves = sorted(set(gt_m.notes_by_staff.keys()) | set(out_m.notes_by_staff.keys()))
        for staff in staves:
            gt_notes = gt_m.notes_by_staff.get(staff, [])
            out_notes = out_m.notes_by_staff.get(staff, [])
            errs = compare_measure_staff(gt_notes, out_notes, num, staff)
            measure_errors.extend(errs)

        compared_measures += 1
        if not measure_errors:
            perfect_measures += 1
        else:
            all_errors.extend(measure_errors)
            # Print this measure's diff
            print(f"\nM{num}:")
            for staff in staves:
                gt_notes = gt_m.notes_by_staff.get(staff, [])
                out_notes = out_m.notes_by_staff.get(staff, [])
                staff_errs = [e for e in measure_errors if e.staff == staff]
                if not staff_errs:
                    continue
                gt_str = " ".join(sorted(n.key() for n in gt_notes))
                out_str = " ".join(sorted(n.key() for n in out_notes))
                if len(staves) > 1:
                    print(f"  Staff {staff}:")
                    prefix = "    "
                else:
                    prefix = "  "
                print(f"{prefix}GT:  {gt_str}")
                print(f"{prefix}Out: {out_str}")
                for e in staff_errs:
                    label = e.category.upper()
                    print(f"{prefix}  - {label}: {e.detail}")

    if not all_errors:
        print("\n  (all measures match perfectly)")

    # --- Section 3: Aggregate summary ---
    print()
    print("=" * 60)
    print("ERROR SUMMARY (covered measures only)")
    print("=" * 60)
    print(f"  Perfect measures: {perfect_measures}/{compared_measures}", end="")
    if compared_measures > 0:
        print(f" ({100 * perfect_measures / compared_measures:.0f}%)")
    else:
        print()

    if not all_errors:
        print("  No errors found!")
        return

    # Count by category
    categories = [
        "missing",
        "extra",
        "octave",
        "accidental",
        "enharmonic",
        "step",
        "rhythm",
        "rest_note_swap",
        "cross_staff",
        "far_pitch",
    ]
    counts: dict[str, int] = dict.fromkeys(categories, 0)
    for e in all_errors:
        counts[e.category] = counts.get(e.category, 0) + 1

