    print(f"\n  Total errors: {total_errors}")
    print()
    print(f"  {'Category':<20} {'Count':>5}  {'%':>5}")
    print(f"  {'-' * 20} {'-' * 5}  {'-' * 5}")
    for cat in categories:
        count = counts[cat]
        if count > 0:
            pct = 100 * count / total_errors
            print(f"  {cat:<20} {count:>5}  {pct:>4.0f}%")

